    let m = grid.len();
    let n = grid[0].len();
    let mut dist = vec![vec![vec![i64::MAX; (k + 1) as usize]; n]; m];
    let mut heap = BinaryHeap::new();

    // Start at (0, 0) with cost 0 and k teleports left
    heap.push(Reverse(State { cost: 0, i: 0, j: 0, k_left: k }));
    dist[0][0][k as usize] = 0;

    while let Some(Reverse(State { cost, i, j, k_left })) = heap.pop() {
        if i == m - 1 && j == n - 1 {
            return cost;
        }

        if cost > dist[i][j][k_left as usize] {
            continue;
        }

        // Regular moves: right and down
        let directions = [(0, 1), (1, 0)];
        for &(di, dj) in directions.iter() {
            let ni = i + di;
            let nj = j + dj;
            if ni < m && nj < n {
                let new_cost = cost + grid[ni][nj];
                if new_cost < dist[ni][nj][k_left as usize] {
                    dist[ni][nj][k_left as usize] = new_cost;
                    heap.push(Reverse(State { cost: new_cost, i: ni, j: nj, k_left }));
                }
            }
        }

        // Teleport moves
        if k_left > 0 {
            for x in 0..m {
                for y in 0..n {
                    if (x != i || y != j) && grid[x][y] <= grid[i][j] {
                        let new_cost = cost;
                        let new_k = k_left - 1;
                        if new_cost < dist[x][y][new_k as usize] {
