    j: usize,
    k_left: i64,
}

fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let mut dist = vec![vec![vec![i64::MAX; (k + 1) as usize]; n]; m];
    let mut heap = BinaryHeap::new();

