    heap.push(Reverse(State {
        cost: 0,
        i: 0,
        j: 0,
        k_left: k,
    }));

    let directions = [(0, 1), (1, 0)];

    while let Some(Reverse(current)) = heap.pop() {
        if current.i == m - 1 && current.j == n - 1 {
            return current.cost;
        }

        if current.cost > dist[current.i][current.j][current.k_left as usize] {
            continue;
        }

        // Normal moves
        for &(di, dj) in &directions {
            let ni = current.i + di;
            let nj = current.j + dj;
            if ni < m && nj < n {
                let new_cost = current.cost + grid[ni][nj];
                if new_cost < dist[ni][nj][current.k_left as usize] {
                    dist[ni][nj][current.k_left as usize] = new_cost;
                    heap.push(Reverse(State {
                        cost: new_cost,
                        i: ni,
                        j: nj,
                        k_left: current.k_left,
                    }));
                }
            }
        }

        // Teleport moves
        if current.k_left > 0 {
            for i in 0..m {
                for j in 0..n {
                    if grid[i][j] <= grid[current.i][current.j] && (i != current.i || j != current.j) {
                        let new_cost = current.cost;
                        let new_k = current.k_left - 1;
                        if new_cost < dist[i][j][new_k as usize] {
                            dist[i][j][new_k as usize] = new_cost;
                            heap.push(Reverse(State {
                                cost: new_cost,
                                i,
                                j,
                                k_left: new_k,
                            }));
                        }
                    }
                }
            }
        }
    }

    *dist[m - 1][n - 1].iter().min().unwrap()
